(function(){'use strict';let countdown=5;let countdownElement=null;let countdownInterval=null;function init(){if(typeof wzBelRedirect==='undefined'||!wzBelRedirect.destination){return}
countdownElement=document.querySelector('.wz-bel-countdown-number');if(!countdownElement){return}
countdown=wzBelRedirect.countdown||5;startCountdown()}
function startCountdown(){updateCountdownDisplay();countdownInterval=setInterval(function(){countdown--;if(countdown<=0){clearInterval(countdownInterval);redirect()}else{updateCountdownDisplay()}},1000)}
function updateCountdownDisplay(){if(countdownElement){countdownElement.textContent=countdown}}
function redirect(){if(wzBelRedirect.destination){window.location.href=wzBelRedirect.destination}}
function cancelRedirect(){if(countdownInterval){clearInterval(countdownInterval)}}
document.addEventListener('click',function(e){if(e.target.closest('.wz-bel-redirect-continue')){return}
cancelRedirect()});document.addEventListener('keydown',function(e){if('Tab'!==e.key){cancelRedirect()}});if('loading'===document.readyState){document.addEventListener('DOMContentLoaded',init)}else{init()}})()